SELECT count(*) FROM char_name, cast_info, title, kind_type, name, aka_name, movie_keyword WHERE cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_keyword.movie_id = title.id;